head.script:
scwin.cvNNew = false;
scwin.cvUpdate = false;
scwin.cvDelete = false;
scwin.cntWorkStandard = 0;
scwin.cntWorkUnit = 0;
scwin.cntFixDriver = 0;
scwin.cntRepairCircularParts = 0;
scwin.cntFixWorkParts = 0;
scwin.txt_vehclShortCd = "";
scwin.txt_taxNo = "";
scwin.txt_slipNo = "";
scwin.saveAction = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RegistFixWorkIndicationCMD.do";

scwin.onpageload = async function() {
    scwin.params = $c.data.getParameter();
};

scwin.onUdcCompleted = async function() {
    $c.gus.cfDisableObjects([txt_fixWrkPlNm, txt_makerNm, txt_eqClssNm, txt_eqKndNm, txt_eqModelNm, txt_posnClsNm, txt_acctDeptNm, txt_assgnLobranNm, txt_damageWrongTyp, em_adptWages]);

    if (scwin.params != null && scwin.params.fixWrkNo != null && scwin.params.fixWrkNo != "") {
        em_fixWrkPlCd.setValue(scwin.params.fixWrkPlCd);
        em_fixWrkNo.setValue(scwin.params.fixWrkNo);
        ds_fix_work.set("homeClsCd", scwin.params.homeClsCd);

        scwin.f_Retrieve();

        scwin.f_ctrlGrdEnable(false);
        scwin.f_ctrlApplyFixWorkStandardBtn(true);
        scwin.f_ctrlGrdBtn(true);
        scwin.f_ioNesYn();

        em_wrkIntendDt.setDisabled(true);
        ica_wrkPlanDt.setDisabled(true);

        scwin.f_setAdjustment();
    } else {
        scwin.cvNNew = true;

        em_fixWrkPlCd.setValue(scwin.params.fixWrkPlCd);
        ds_fix_work.set("homeClsCd", scwin.params.homeClsCd);

        scwin.f_openCommonPopUp(1, em_fixWrkPlCd.getValue(), '', 'T', 'T');

        scwin.f_ctrlApplyFixWorkStandardBtn(false);
        scwin.f_ctrlGrdBtn(false);
        scwin.f_ctrlFixKndCd();

        lux_fixKndCd.setSelectedIndex(0);
        lux_fixCauseCd.setSelectedIndex(2);
        lux_selfOutordClsCd.setSelectedIndex(0);
        lux_fixCatCd.setSelectedIndex(0);

        $c.gus.cfDisableObjects([txt_accdRecptNo, em_circulPartCd, txt_circulPartNm]);
        btn_accdRecptNo.setDisabled(true);

        chk_ioNesYn.setValue("1");
        scwin.f_ioNesYn();

        em_fixWrkPlCd.setFocus();
    }

    scwin.f_selfOutordCls();

    scwin.saveAction = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RegistFixWorkIndicationCMD.do";

    ds_fix_work.set("applyFixWorkStandardYn", "0");

    lux_fixWrkStsCd.setValue("I");
};

scwin.f_Retrieve = async function() {
    ds_fix_work_re.set("fixWrkPlCd", em_fixWrkPlCd.getValue());
    ds_fix_work_re.set("fixWrkNo", em_fixWrkNo.getValue());

    sbm_retrieve.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RetrieveFixWorkCMD.do";
    await $c.sbm.execute(sbm_retrieve);

    ds_fix_work.set("applyFixWorkStandardYn", "0");

    $c.gus.cfDisableObjects([btn_Save_center]);

    $c.gus.cfDisableKeyData();
};

scwin.sbm_retrieve_submitdone = function(e) {
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_applyFixWorkStandard_submitdone = function(e) {
};

scwin.sbm_applyFixWorkStandard_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_applyFixWorkUnit_submitdone = function(e) {
};

scwin.sbm_applyFixWorkUnit_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_save_submitdone = async function(e) {
    if (scwin.cvDelete == true) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_004);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    }
};

scwin.sbm_save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.btn_Edit_center_onclick = function(e) {
    scwin.f_Update();
};

scwin.btn_Save_center_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_Del_center_onclick = function(e) {
    scwin.f_Delete();
};

scwin.btn_Close_center_onclick = function(e) {
    $c.win.closePopup();
};

scwin.btn_ApplyFixWorkStandard_onclick = function(e) {
    scwin.f_ApplyFixWorkStandard();
};

scwin.btn_ApplyFixWorkStandard2_onclick = function(e) {
    scwin.f_ApplyFixWorkStandard();
};

scwin.f_Update = async function() {
    scwin.saveAction = "/ps.eq.fixwrkmgnt.fixwrkmgnt.UpdateFixWorkIndicationCMD.do";

    scwin.cvUpdate = true;

    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();

    $c.gus.cfDisableObjects([btn_Edit_center]);

    $c.gus.cfEnableObjects([ica_inDt, ica_outDt, em_wrkIntendDt, em_endIntendDt, ica_wrkStDt, ica_wrkEndDt, ica_expireDt]);

    scwin.f_ctrlApplyFixWorkStandardBtn(false);
    scwin.f_ctrlGrdBtn(false);

    lux_selfOutordClsCd.setDisabled(true);

    scwin.f_ctrlFixKndCd();

    ica_wrkPlanDt.setDisabled(true);

    ds_fix_work.set("applyFixWorkStandardYn", "0");

    scwin.f_ctrlGrdEnable(true);
};

scwin.f_Save = async function() {
    if (!(await scwin.f_SaveValid("SaveTemporary"))) return;

    if (ds_fix_work.isUpdated() == false && ds_fix_work_standard.getUpdatedIndex().length == 0 && ds_fix_work_unit.getUpdatedIndex().length == 0 &&
        ds_fix_driver.getUpdatedIndex().length == 0 && ds_repair_circula_parts.getUpdatedIndex().length == 0 && ds_fix_work_parts.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["작업지시 기본정보 및 상세정보"]);
    } else {
        if ((ica_wrkStDt.getValue() + "" + em_wrkStHh.getValue()) > (ica_wrkEndDt.getValue() + "" + em_wrkEndHh.getValue())) {
            await $c.win.alert("작업시작일시를 작업완료일시 이전으로 입력하여 주십시오.");
            ica_wrkStDt.setFocus();
            return;
        }

        if ((ica_inDt.getValue() + "" + em_inHh.getValue()) > (ica_outDt.getValue() + "" + em_outHh.getValue())) {
            await $c.win.alert("입고일시를 출고일시 이전으로 입력하여 주십시오");
            ica_inDt.setFocus();
            return;
        }

        ds_fix_work.set("vehclNo", txt_vehclNo.getValue());
        if (ica_wrkStDt.getValue() != "" && ica_wrkEndDt.getValue() != "") {
            em_needDt.setValue($c.date.diffDate(ica_wrkStDt.getValue(), ica_wrkEndDt.getValue()));
        }

        if (scwin.cvUpdate == true) {
            // TODO: ds_fix_work.UseChangeInfo = false equivalent
        }

        for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
            if (ds_fix_work_parts.getCellData(row, "partQty") == "0") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_013, ["소요부품의 사용수량", "0"]);
                return;
            }
        }

        sbm_save.action = scwin.saveAction;
        await $c.sbm.execute(sbm_save);

        $c.gus.cfDisableKeyData();

        $c.gus.cfDisableObjects([btn_Save_center]);

        scwin.f_ctrlApplyFixWorkStandardBtn(true);
        scwin.f_ctrlGrdBtn(true);

        scwin.f_ctrlGrdEnable(false);

        em_fixWrkPlCd.setReadOnly(true);

        scwin.f_Retrieve();
    }
};

scwin.f_SaveValid = async function(saveType) {
    $c.gus.cfRefreshMandSign();

    let chk = await $c.gus.cfValidate([tb_work]);
    if (!chk) return false;

    if (saveType == "SaveTemporary") {
        let chk2 = await $c.gus.cfValidate([tbl_eq]);
        if (!chk2) return false;
        let chk3 = await $c.gus.cfValidate([em_wrkIntendDt, em_endIntendDt]);
        if (!chk3) return false;

        if (em_wrkIntendDt.getValue() != "" && em_endIntendDt.getValue() != "") {
            if (!$c.gus.cfIsAfterDate(em_wrkIntendDt.getValue(), em_endIntendDt.getValue())) {
                await $c.win.alert("작업예정일자는 종료예정일자 이전이어야 합니다.");
                ica_wrkStDt.setFocus();
                return false;
            }
        }

        if (ica_wrkStDt.getValue().trim() != "" && ica_wrkEndDt.getValue().trim() != "") {
            if (ds_fix_work.get("homeClsCd") == "TR") {
                let stYm = ica_wrkStDt.getValue().trim().substring(0, 6);
                let edYm = ica_wrkEndDt.getValue().trim().substring(0, 6);
                if (stYm != edYm) {
                    await $c.win.alert("작업시작월과 종료월은 동일 해야 합니다.");
                    return false;
                }
            }
        }
    }

    ds_fix_work.set("vehclNo", txt_vehclNo.getValue());

    if (ica_wrkStDt.getValue() != "" && ica_wrkEndDt.getValue() != "") {
        em_needDt.setValue($c.date.diffDate(ica_wrkStDt.getValue(), ica_wrkEndDt.getValue()));
    }

    return true;
};

scwin.f_Delete = async function() {
    let chk = await $c.win.confirm("삭제하시겠습니까?");
    if (chk) {
        scwin.cvDelete = true;

        sbm_save.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.DeleteFixWorkIndicationCMD.do";
        await $c.sbm.execute(sbm_save);

        $c.win.closePopup("REFRESH");
    }
};

scwin.f_DeleteMarked = function() {
    let pos = ds_fix_work_unit.getRowPosition();
    if (pos < 0) return;
    let fixWrkUnitNo = ds_fix_work_unit.getCellData(pos, "fixWrkUnitNo");

    for (let row = ds_fix_work_parts.getRowCount() - 1; row >= 0; row--) {
        if (ds_fix_work_parts.getCellData(row, "fixWrkUnitNo") == fixWrkUnitNo) {
            ds_fix_work_parts.removeRow(row);
        }
    }
    for (let row = ds_fix_driver.getRowCount() - 1; row >= 0; row--) {
        if (ds_fix_driver.getCellData(row, "fixWrkUnitNo") == fixWrkUnitNo) {
            ds_fix_driver.removeRow(row);
        }
    }
};

scwin.f_UndoMarked = function() {
    let pos = ds_fix_work_unit.getRowPosition();
    if (pos < 0) return;
    let fixWrkUnitNo = ds_fix_work_unit.getCellData(pos, "fixWrkUnitNo");

    for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
        if (ds_fix_work_parts.getCellData(row, "fixWrkUnitNo") == fixWrkUnitNo) {
            ds_fix_work_parts.undoRow(row);
        }
    }
    for (let row = 0; row < ds_fix_driver.getRowCount(); row++) {
        if (ds_fix_driver.getCellData(row, "fixWrkUnitNo") == fixWrkUnitNo) {
            ds_fix_driver.undoRow(row);
        }
    }
};

scwin.f_OzReport = function() {
    let odiParam = new ODIParam("eq_330_01_01b");
    odiParam.add("fixWrkPlCd", em_fixWrkPlCd.getValue());
    odiParam.add("fixWrkNo", em_fixWrkNo.getValue());

    let formParam = new FormParam();
    let viewerParam = new ViewerParam();
    viewerParam.add("viewer.useprogressbar", "false");

    $c.gus.cfOZReport("chb_printCheck", "chb_previewCheck", "/ps/eq/fixwrkmgnt/fixwrkmgnt/eq_330_01_01b.ozr", odiParam, viewerParam, formParam);
};

scwin.f_OzReport2 = function() {
    let odiParam = new ODIParam("eq_330_01_02b");
    odiParam.add("fixWrkPlCd", em_fixWrkPlCd.getValue());
    odiParam.add("fixWrkNo", em_fixWrkNo.getValue());

    let formParam = new FormParam();
    let viewerParam = new ViewerParam();
    viewerParam.add("viewer.useprogressbar", "false");

    $c.gus.cfOZReport("chb_printCheck", "chb_previewCheck", "/ps/eq/fixwrkmgnt/fixwrkmgnt/eq_330_01_02b.ozr", odiParam, viewerParam, formParam);
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;

    switch (disGubun) {
        case 1:
            rtnList = $c.gus.cfCommonPopUp('retrieveWorkPlaceInfo', pCode, pName, pClose, null, null, null, null, scwin.params.homeClsCd, null, null, null, null, null, pAllSearch, "작업장조회,작업장코드,작업장명");
            $c.gus.cfSetReturnValue(rtnList, em_fixWrkPlCd, txt_fixWrkPlNm);
            if (rtnList != null && rtnList[0] != "N/A") {
                em_adptWages.setValue(parseInt(rtnList[3]));
            }
            break;

        case 2:
            let argDt = "";
            if (ica_wrkEndDt.getValue().trim() == "") {
                argDt = "XXXX";
            } else {
                argDt = ica_wrkEndDt.getValue().trim();
            }
            rtnList = $c.gus.cfCommonPopUp('retrieveEqBasicListInfo', pCode, pName, pClose, null, null, null, null, scwin.params.homeClsCd + ",,," + argDt, null, null, null, null, null, pAllSearch, "장비,장비코드,차량번호");

            if (rtnList != null && rtnList[0] != "N/A") {
                em_eqCd.setValue(rtnList[0]);
                txt_vehclNo.setValue(rtnList[1]);
                scwin.txt_vehclShortCd = rtnList[2];
                txt_makerNm.setValue(rtnList[4]);
                txt_eqClssNm.setValue(rtnList[5]);
                txt_eqKndNm.setValue(rtnList[6]);
                txt_eqModelNm.setValue(rtnList[3]);
                txt_posnClsNm.setValue(rtnList[7]);
                txt_acctDeptNm.setValue(rtnList[8]);
                txt_assgnLobranNm.setValue(rtnList[9]);
            } else {
                em_eqCd.setValue("");
                txt_vehclNo.setValue("");
                scwin.txt_vehclShortCd = "";
                txt_makerNm.setValue("");
                txt_eqClssNm.setValue("");
                txt_eqKndNm.setValue("");
                txt_eqModelNm.setValue("");
                txt_posnClsNm.setValue("");
                txt_acctDeptNm.setValue("");
                txt_assgnLobranNm.setValue("");
            }
            break;

        case 3:
            rtnList = $c.gus.cfCommonPopUp('retrieveFixClntList', pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "외주정비거래처조회,거래처코드,거래처명");
            $c.gus.cfSetReturnValue(rtnList, em_outordFixClntNo, txt_outordFixClntNm);
            break;

        case 4:
            rtnList = $c.gus.cfCommonPopUp('retrievePartYnInfo', pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "수리순환부품조회,부품코드,부품명");
            $c.gus.cfSetReturnValue(rtnList, em_circulPartCd, txt_circulPartNm);
            if (rtnList != null && rtnList[0] != "N/A") {
                txt_circulPartNm.setFocus();
            }
            break;

        case 6:
            rtnList = $c.gus.cfCommonPopUp('retrieveAccdNoInfo', pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, txt_accdRecptNo, null, [txt_damageWrongTyp]);
            break;

        default:
            break;
    }
};

scwin.f_chkOpenCommonPopUp = function(disGubun, inObj, pairObj, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        if (disGubun == 2) {
            txt_makerNm.setValue("");
            txt_eqClssNm.setValue("");
            txt_eqKndNm.setValue("");
            txt_eqModelNm.setValue("");
            txt_posnClsNm.setValue("");
            txt_acctDeptNm.setValue("");
            txt_assgnLobranNm.setValue("");
        } else if (disGubun == 1) {
            em_adptWages.setValue("0");
        }
        return;
    }

    $c.gus.cfClearPairObj(pairObj);

    if (disGubun == 2) {
        txt_makerNm.setValue("");
        txt_eqClssNm.setValue("");
        txt_eqKndNm.setValue("");
        txt_eqModelNm.setValue("");
        txt_posnClsNm.setValue("");
        txt_acctDeptNm.setValue("");
        txt_assgnLobranNm.setValue("");
    } else if (disGubun == 1) {
        em_adptWages.setValue("0");
    }

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_openCommPopUpGrid = function(disGubun, row, pClose) {
    let rtnList;
    let pCode = "";
    let pName = "";
    let sameFixWrkUnitNo = 0;

    switch (disGubun) {
        case 1:
            pCode = ds_fix_work_standard.getCellData(row, "fixWrkStndNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveFixWrkSdListInfo', pCode, pName, pClose, null, null, null, null, scwin.params.homeClsCd, null, null, null, null, null, "T", "작업표준정보,작업표준코드,작업표준명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_standard, row, "fixWrkStndNo", "wrkStndNm");
            break;

        case 2:
            pCode = ds_fix_work_unit.getCellData(row, "fixWrkUnitNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveFixWrkUnitListInfo', pCode, pName, pClose, null, null, null, null, scwin.params.homeClsCd, null, null, null, null, null, "F", "작업단위정보,작업단위코드,작업단위명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_unit, row, "fixWrkUnitNo", "fixWrkUnitNm", ["stndWrkHhCnt"]);
            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                scwin.f_applyFixWorkUnit(row, rtnList[0]);
            }
            break;

        case 3:
            pCode = ds_fix_driver.getCellData(row, "fixWrkUnitNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveFixWrkUnitListInfo', pCode, pName, pClose, null, null, null, null, scwin.params.homeClsCd, null, null, null, null, null, "F", "작업단위정보,작업단위코드,작업단위명");

            sameFixWrkUnitNo = 0;
            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                for (let i = 0; i < ds_fix_work_unit.getRowCount(); i++) {
                    if (ds_fix_work_unit.getCellData(i, "fixWrkUnitNo") == rtnList[0]) {
                        sameFixWrkUnitNo = 1;
                        break;
                    }
                }
                if (sameFixWrkUnitNo == 0) {
                    ds_fix_driver.setCellData(ds_fix_driver.getRowPosition(), "fixWrkUnitNo", "");
                    alert("작업단위에 등록된 작업단위번호만 입력가능합니다.");
                    return false;
                }
            }
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_driver, row, "fixWrkUnitNo", "");
            break;

        case 4:
            pName = ds_fix_driver.getCellData(row, "fixEmpNm");
            let addWhere4 = "," + scwin.params.fixWrkPlCd + ",2";
            rtnList = $c.gus.cfCommonPopUp('retrieveFixEmpInfo', pCode, pName, pClose, null, null, null, null, addWhere4, null, null, null, null, null, "T", "정비사정보,정비사코드,정비사명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_driver, row, "fixEmpNo", "fixEmpNm");
            break;

        case 5:
            pCode = ds_repair_circula_parts.getCellData(row, "circulPartCd");
            rtnList = $c.gus.cfCommonPopUp('retrievePartYnInfo', pCode, pName, pClose, null, null, null, null, scwin.params.homeClsCd, null, null, null, null, null, "T", "수리순환품정보,부품코드,부품명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_repair_circula_parts, row, "circulPartCd", "circulPartNm");
            break;

        case 6:
            pCode = ds_fix_work_parts.getCellData(row, "fixWrkUnitNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveFixWrkUnitListInfo', pCode, pName, pClose, null, null, null, null, scwin.params.homeClsCd, null, null, null, null, null, "F", "작업단위정보,작업단위코드,작업단위명");

            sameFixWrkUnitNo = 0;
            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                for (let i = 0; i < ds_fix_work_unit.getRowCount(); i++) {
                    if (ds_fix_work_unit.getCellData(i, "fixWrkUnitNo") == rtnList[0]) {
                        sameFixWrkUnitNo = 1;
                        break;
                    }
                }
                if (sameFixWrkUnitNo == 0) {
                    ds_fix_work_parts.setCellData(ds_fix_work_parts.getRowPosition(), "fixWrkUnitNo", "");
                    alert("작업단위에 등록된 작업단위번호만 입력가능합니다.");
                    return false;
                }
            }
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_parts, row, "fixWrkUnitNo", "");
            break;

        case 7:
            pCode = ds_fix_work_parts.getCellData(row, "partCd");
            let addWhere7 = em_fixWrkPlCd.getValue() + "," + ds_fix_work_parts.getCellData(ds_fix_work_parts.getRowPosition(), "inClsCd");
            rtnList = $c.gus.cfCommonPopUp('retrievePartBasicInfo', pCode, pName, pClose, null, null, null, null, addWhere7, null, null, null, null, null, "T", "부품정보,부품코드,부품명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_parts, row, "partCd", "partNm");

            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                ds_fix_work_parts.setCellData(row, "partUnitNm", rtnList[3]);
                ds_fix_work_parts.setCellData(row, "clntNm", "");
                ds_fix_work_parts.setCellData(row, "clntNo", "");
                ds_fix_work_parts.setCellData(row, "stockQty", rtnList[7]);
                ds_fix_work_parts.setCellData(row, "outUpr", Math.round(rtnList[6] / rtnList[7]));

                if (ds_fix_work_parts.getCellData(row, "partQty") == "0") {
                    ds_fix_work_parts.setCellData(row, "totAmt", "0");
                    ds_fix_work_parts.setCellData(row, "vatAmt", "0");
                } else {
                    ds_fix_work_parts.setCellData(row, "totAmt", ds_fix_work_parts.getCellData(row, "partQty") * ds_fix_work_parts.getCellData(row, "outUpr"));
                    ds_fix_work_parts.setCellData(row, "vatAmt", ds_fix_work_parts.getCellData(row, "totAmt") / 10);
                }
            }
            break;

        case 8:
            pCode = em_fixWrkPlCd.getValue();
            pName = ds_fix_work_parts.getCellData(row, "partCd");
            let addWhere8 = ds_fix_work_parts.getCellData(row, "inClsCd");
            rtnList = $c.gus.cfCommonPopUp('retrieveStockCustomer', pCode, pName, pClose, null, null, null, null, addWhere8, null, null, null, null, null, "T", "부품정보,정비작업장,부품코드");

            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_parts, row, "clntNm", "totAmt");
                ds_fix_work_parts.setCellData(row, "clntNo", rtnList[3]);
                ds_fix_work_parts.setCellData(row, "outUpr", rtnList[1] / rtnList[2]);

                if (ds_fix_work_parts.getCellData(row, "partQty") == "0") {
                    ds_fix_work_parts.setCellData(row, "totAmt", "0");
                    ds_fix_work_parts.setCellData(row, "vatAmt", "0");
                } else {
                    ds_fix_work_parts.setCellData(row, "totAmt", ds_fix_work_parts.getCellData(row, "partQty") * ds_fix_work_parts.getCellData(row, "outUpr"));
                    ds_fix_work_parts.setCellData(row, "vatAmt", ds_fix_work_parts.getCellData(row, "totAmt") / 10);
                }
            } else {
                ds_fix_work_parts.setCellData(row, "inClsCd", "2");
                ds_fix_work_parts.setCellData(row, "clntNo", "");
                ds_fix_work_parts.setCellData(row, "outUpr", 0);
                ds_fix_work_parts.setCellData(row, "vatAmt", 0);
            }
            break;
    }
};

scwin.f_AddRow = async function(grd) {
    if (scwin.cvUpdate == false && scwin.cvNNew == false) return;

    switch (grd) {
        case 1:
            ds_fix_work_standard.insertRow(ds_fix_work_standard.getRowCount());
            let stdPos = ds_fix_work_standard.getRowPosition();
            ds_fix_work_standard.setCellData(stdPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_fix_work_standard.setCellData(stdPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_fix_work_standard.setCellData(stdPos, "homeClsCd", scwin.params.homeClsCd);
            break;

        case 2:
            ds_fix_work_unit.insertRow(ds_fix_work_unit.getRowCount());
            let unitPos = ds_fix_work_unit.getRowPosition();
            ds_fix_work_unit.setCellData(unitPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_fix_work_unit.setCellData(unitPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_fix_work_unit.setCellData(unitPos, "homeClsCd", scwin.params.homeClsCd);
            break;

        case 3:
            ds_fix_driver.insertRow(ds_fix_driver.getRowCount());
            let drvPos = ds_fix_driver.getRowPosition();
            ds_fix_driver.setCellData(drvPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_fix_driver.setCellData(drvPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_fix_driver.setCellData(drvPos, "homeClsCd", scwin.params.homeClsCd);
            let unitRowPos3 = ds_fix_work_unit.getRowPosition();
            if (unitRowPos3 >= 0) {
                ds_fix_driver.setCellData(drvPos, "fixWrkUnitNo", ds_fix_work_unit.getCellData(unitRowPos3, "fixWrkUnitNo"));
            }
            break;

        case 4:
            ds_repair_circula_parts.insertRow(ds_repair_circula_parts.getRowCount());
            let repPos = ds_repair_circula_parts.getRowPosition();
            ds_repair_circula_parts.setCellData(repPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_repair_circula_parts.setCellData(repPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_repair_circula_parts.setCellData(repPos, "homeClsCd", scwin.params.homeClsCd);
            break;

        case 5:
            ds_fix_work_parts.insertRow(ds_fix_work_parts.getRowCount());
            let partPos = ds_fix_work_parts.getRowPosition();
            ds_fix_work_parts.setCellData(partPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_fix_work_parts.setCellData(partPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_fix_work_parts.setCellData(partPos, "inClsCd", "1");
            ds_fix_work_parts.setCellData(partPos, "homeClsCd", scwin.params.homeClsCd);
            let unitRowPos5 = ds_fix_work_unit.getRowPosition();
            if (unitRowPos5 >= 0) {
                ds_fix_work_parts.setCellData(partPos, "fixWrkUnitNo", ds_fix_work_unit.getCellData(unitRowPos5, "fixWrkUnitNo"));
            }
            break;
    }
};

scwin.f_ApplyFixWorkStandard = async function() {
    if ((scwin.cvNNew == false && scwin.cvUpdate == false) || ds_fix_work_standard.getRowCount() < 1) return;

    for (let row = 0; row < ds_fix_work_standard.getRowCount(); row++) {
        if (ds_fix_work_standard.getCellData(row, "fixWrkStndNo") == "") return;
    }

    if (ds_fix_work_unit.getUpdatedIndex().length > 0 || ds_fix_work_parts.getUpdatedIndex().length > 0) {
        let chk = await $c.gus.cfConfirmMsg(MSG_CM_CRM_005);
        if (!chk) {
            return;
        }
    }

    ds_fix_work_unit.removeAll();
    ds_fix_work_parts.removeAll();
    ds_fix_driver.removeAll();

    for (let row = 0; row < ds_fix_work_standard.getRowCount(); row++) {
        ds_fix_work_standard.setCellData(row, "eqCd", em_eqCd.getValue());
        ds_fix_work_standard.setCellData(row, "homeClsCd", scwin.params.homeClsCd);
    }

    sbm_applyFixWorkStandard.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.ApplyFixWorkStandardCMD.do";
    await $c.sbm.execute(sbm_applyFixWorkStandard);

    for (let row = 0; row < ds_fix_work_unit_apply.getRowCount(); row++) {
        ds_fix_work_unit.insertRow(ds_fix_work_unit.getRowCount());
        let newPos = ds_fix_work_unit.getRowCount() - 1;
        let cols = ["fixWrkStndNo", "fixWrkUnitNo", "fixWrkUnitNm", "homeClsCd", "fixWrkPlCd", "fixWrkNo", "stndWrkHhCnt", "wrkHhCnt", "bilgWages", "dayNgtClsCd", "offDayClsCd"];
        for (let c = 0; c < cols.length; c++) {
            ds_fix_work_unit.setCellData(newPos, cols[c], ds_fix_work_unit_apply.getCellData(row, cols[c]));
        }
    }

    if (lux_selfOutordClsCd.getValue() == "IN") {
        for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
            if (ds_fix_work_unit.getRowStatus(row) != "C") continue;
            if (ds_fix_work_unit.getCellData(row, "fixWrkUnitNo") == "") continue;
            scwin.f_AddRow(3);
            ds_fix_driver.setCellData(ds_fix_driver.getRowPosition(), "fixWrkUnitNo", ds_fix_work_unit.getCellData(row, "fixWrkUnitNo"));
        }
    }

    for (let row = 0; row < ds_fix_work_parts_apply.getRowCount(); row++) {
        ds_fix_work_parts.insertRow(ds_fix_work_parts.getRowCount());
        let newPos = ds_fix_work_parts.getRowCount() - 1;
        let cols = ["fixWrkPlCd", "fixWrkNo", "seq", "fixWrkUnitNo", "homeClsCd", "partCd", "partNm", "partUnitCd", "partUnitNm", "partQty", "inClsCd", "clntNo", "clntNm", "capExpdYn", "stockQty", "useExpectQty", "catCd", "catNm", "partMakerCd", "partMakerNm", "outUpr", "bilgAmt", "vatAmt", "totAmt", "partOutNo"];
        for (let c = 0; c < cols.length; c++) {
            ds_fix_work_parts.setCellData(newPos, cols[c], ds_fix_work_parts_apply.getCellData(row, cols[c]));
        }
    }

    ds_fix_work.set("applyFixWorkStandardYn", "1");
};

scwin.f_applyFixWorkUnit = async function(row, fixWrkUnitNo) {
    sbm_applyFixWorkUnit.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.ApplyFixWorkUnitCMD.do?fixWorkUnitNumber="
        + fixWrkUnitNo + "&homeClsCd=" + scwin.params.homeClsCd + "&eqCd=" + em_eqCd.getValue() + "&fixWrkPlCd=" + em_fixWrkPlCd.getValue();
    await $c.sbm.execute(sbm_applyFixWorkUnit);

    for (let r = 0; r < ds_fix_work_parts_apply.getRowCount(); r++) {
        ds_fix_work_parts.insertRow(ds_fix_work_parts.getRowCount());
        let partRow = ds_fix_work_parts.getRowCount() - 1;

        ds_fix_work_parts.setCellData(partRow, "fixWrkPlCd", em_fixWrkPlCd.getValue());
        ds_fix_work_parts.setCellData(partRow, "fixWrkNo", em_fixWrkNo.getValue());
        ds_fix_work_parts.setCellData(partRow, "fixWrkUnitNo", ds_fix_work_parts_apply.getCellData(r, "fixWrkUnitNo"));
        ds_fix_work_parts.setCellData(partRow, "partCd", ds_fix_work_parts_apply.getCellData(r, "partCd"));
        ds_fix_work_parts.setCellData(partRow, "partNm", ds_fix_work_parts_apply.getCellData(r, "partNm"));
        ds_fix_work_parts.setCellData(partRow, "partUnitNm", ds_fix_work_parts_apply.getCellData(r, "partUnitNm"));
        ds_fix_work_parts.setCellData(partRow, "inClsCd", "1");
        ds_fix_work_parts.setCellData(partRow, "outUpr", ds_fix_work_parts_apply.getCellData(r, "outUpr"));
        ds_fix_work_parts.setCellData(partRow, "partQty", ds_fix_work_parts_apply.getCellData(r, "partQty"));
        ds_fix_work_parts.setCellData(partRow, "stockQty", ds_fix_work_parts_apply.getCellData(r, "stockQty"));
    }
};

