};

scwin.f_ctrlGrdEnable = function(ctrl) {
    if (lux_selfOutordClsCd.getValue() == "IN") {
        gr_fix_work_standard.setReadOnly("grid", !ctrl);
        gr_fix_work_unit.setReadOnly("grid", !ctrl);
        gr_fix_driver.setReadOnly("grid", !ctrl);
        gr_repair_circula_parts.setReadOnly("grid", !ctrl);
        gr_fix_work_parts.setReadOnly("grid", !ctrl);
    } else {
        gr_fix_work_standard2.setReadOnly("grid", !ctrl);
        gr_fix_work_unit2.setReadOnly("grid", !ctrl);
        gr_repair_circula_parts2.setReadOnly("grid", !ctrl);
    }
};

scwin.f_ctrlGrdBtn = function(ctrl) {
    let cursor = ctrl ? "default" : "pointer";
    let btnAddRows = document.querySelectorAll("[id='btn_grdAddRow']");
    let btnDelRows = document.querySelectorAll("[id='btn_grdDelRow']");
    let btnCanRows = document.querySelectorAll("[id='btn_grdCanRow']");

    if (typeof $p != "undefined" && $p.getComponentsByType) {
        let allTriggers = $p.getComponentsByType("trigger");
        for (let i = 0; i < allTriggers.length; i++) {
            let tId = allTriggers[i].getID ? allTriggers[i].getID() : "";
            if (tId == "btn_grdAddRow" || tId == "btn_grdDelRow" || tId == "btn_grdCanRow") {
                allTriggers[i].setDisabled(ctrl);
            }
        }
    }
};

scwin.f_GrdHeight = function(objGrdId, size) {
    let objGrd = $p.getComponentById(objGrdId);
    if (objGrd) {
        let currentHeight = parseInt(objGrd.getStyle("height") || "0");
        let newHeight = currentHeight + size;
        if (newHeight > 0) {
            objGrd.setStyle("height", newHeight + "px");
        }
    }
};

scwin.f_ioNesYn = function() {
    let checked = (chk_ioNesYn.getValue() == "1" || chk_ioNesYn.getValue() == true);
    if (checked) {
        em_inHh.setDisabled(false);
        em_outHh.setDisabled(false);
        ica_inDt.setDisabled(false);
        ica_outDt.setDisabled(false);
    } else {
        ica_inDt.setValue("");
        em_inHh.setValue("");
        ica_outDt.setValue("");
        em_outHh.setValue("");

        em_inHh.setDisabled(true);
        em_outHh.setDisabled(true);
        ica_inDt.setDisabled(true);
        ica_outDt.setDisabled(true);
    }
    $c.gus.cfRefreshMandSign();
};

scwin.f_ctrlFixKndCd = async function() {
    chk_ioNesYn.setValue("1");
    chk_ioNesYn.setDisabled(true);

    $c.gus.cfDisableObjects([txt_accdRecptNo, btn_accdRecptNo]);

    if (lux_fixKndCd.getValue() == "02") {
        $c.gus.cfEnableObjects([txt_accdRecptNo, btn_accdRecptNo]);

        $c.gus.cfDisableObjects([em_circulPartCd, txt_circulPartNm]);
    } else if (lux_fixKndCd.getValue() == "04") {
        $c.gus.cfEnableObjects([em_circulPartCd, txt_circulPartNm]);
        em_circulPartCd.setFocus();

        chk_ioNesYn.setValue("0");
        chk_ioNesYn.setDisabled(true);
        scwin.f_ioNesYn();

        txt_damageWrongTyp.setValue("");
    } else {
        txt_damageWrongTyp.setValue("");

        $c.gus.cfDisableObjects([em_circulPartCd, txt_circulPartNm]);
    }

    $c.gus.cfRefreshMandSign();
};

scwin.f_selfOutordCls = async function() {
    if (lux_selfOutordClsCd.getValue() == "OT") {
        $c.gus.cfEnableObjects([em_outordFixClntNo, txt_outordFixClntNm]);
    } else {
        em_outordFixClntNo.setValue("");
        txt_outordFixClntNm.setValue("");
        $c.gus.cfDisableObjects([em_outordFixClntNo, txt_outordFixClntNm]);
    }
    $c.gus.cfRefreshMandSign();
};

scwin.f_RetrieveStockCustomer = function(row) {
    switch (ds_fix_work_parts.getCellData(row, "inClsCd")) {
        case "1":
            if (ds_fix_work_parts.getCellData(row, "partCd") == "") return;
            scwin.f_openCommPopUpGrid(7, row, 'T');
            break;

        case "2":
            ds_fix_work_parts.setCellData(row, "clntNo", "");
            ds_fix_work_parts.setCellData(row, "clntNm", "");
            ds_fix_work_parts.setCellData(row, "outUpr", 0);
            ds_fix_work_parts.setCellData(row, "totAmt", 0);
            ds_fix_work_parts.setCellData(row, "vatAmt", 0);
            break;

        case "3":
            if (ds_fix_work_parts.getCellData(row, "partCd") == "") return;
            scwin.f_openCommPopUpGrid(8, row, 'T');
            break;
    }
};

scwin.f_setIntendDt = function() {
    if (em_wrkIntendDt.getValue() == "" && ica_wrkStDt.getValue() != "") {
        em_wrkIntendDt.setValue(ica_wrkStDt.getValue());
    }
    if (em_endIntendDt.getValue() == "" && ica_wrkEndDt.getValue() != "") {
        em_endIntendDt.setValue(ica_wrkEndDt.getValue());
    }
};

scwin.f_setAdjustment = function() {
    let partAmt = 0;
    if (em_partAmt.getValue() == "") em_partAmt.setValue("0");
    for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
        partAmt = parseInt(em_partAmt.getValue()) + parseInt(ds_fix_work_parts.getCellData(row, "totAmt") || "0");
    }
    em_partAmt.setValue(partAmt);

    if (em_wages.getValue() == "") em_wages.setValue("0");

    if (lux_selfOutordClsCd.getValue() == "IN") {
        let wages = 0;
        for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
            if (em_adptWages.getValue() == "") em_adptWages.setValue("0");
            if (em_adptWages.getValue() != "0" && ds_fix_work_unit.getCellData(row, "wrkHhCnt") != "0") {
                wages += parseInt(em_adptWages.getValue()) * parseInt(ds_fix_work_unit.getCellData(row, "wrkHhCnt") || "0");
            }
        }
        em_wages.setValue(wages);
        em_totAmt.setValue(parseInt(em_partAmt.getValue()));
    } else {
        let wages = 0;
        for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
            wages += parseInt(ds_fix_work_unit.getCellData(row, "bilgWages") || "0");
        }
        em_wages.setValue(wages);
        em_totAmt.setValue(parseInt(em_wages.getValue()) + parseInt(em_partAmt.getValue()));
    }

    if (em_totAmt.getValue() != "") {
        em_vatAmt.setValue(parseFloat(em_totAmt.getValue()) / 10);
    }
};

scwin.lux_fixKndCd_onchange = function(e) {
    scwin.f_ctrlFixKndCd();
};

scwin.lux_selfOutordClsCd_onchange = async function(e) {
    if (ds_fix_work_standard.getUpdatedIndex().length > 0 || ds_fix_work_unit.getUpdatedIndex().length > 0 ||
        ds_fix_driver.getUpdatedIndex().length > 0 || ds_repair_circula_parts.getUpdatedIndex().length > 0 ||
        ds_fix_work_parts.getUpdatedIndex().length > 0) {

        let chk = await $c.gus.cfConfirmMsg(MSG_CM_CRM_005);
        if (!chk) {
            if (lux_selfOutordClsCd.getValue() == "IN") {
                lux_selfOutordClsCd.setValue("OT");
            } else {
                lux_selfOutordClsCd.setValue("IN");
            }
            return;
        }
    }

    ds_fix_work_standard.removeAll();
    ds_fix_work_unit.removeAll();
    ds_fix_driver.removeAll();
    ds_repair_circula_parts.removeAll();
    ds_fix_work_parts.removeAll();

    scwin.f_selfOutordCls();
};

scwin.gr_fix_work_standard_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    scwin.f_openCommPopUpGrid(1, rowIndex, 'F');
};

scwin.gr_fix_work_standard_oneditend = function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    if (rowIndex >= 0 && ds_fix_work_standard.getRowCount() > rowIndex) {
        switch (columnId) {
            case "fixWrkStndNo":
                if (ds_fix_work_standard.getCellData(rowIndex, columnId) != "" && ds_fix_work_standard.getCellData(rowIndex, columnId) != oldValue) {
                    ds_fix_work_standard.setCellData(rowIndex, "wrkStndNm", "");
                    scwin.f_openCommPopUpGrid(1, rowIndex, 'T');
                } else if (ds_fix_work_standard.getCellData(rowIndex, columnId) == "") {
                    ds_fix_work_standard.setCellData(rowIndex, "fixWrkStndNo", "");
                    ds_fix_work_standard.setCellData(rowIndex, "wrkStndNm", "");
                }
                break;
        }
    }
};

scwin.gr_fix_work_unit_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    scwin.f_openCommPopUpGrid(2, rowIndex, 'F');
};

scwin.gr_fix_work_unit_oneditend = function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    if (rowIndex >= 0 && ds_fix_work_unit.getRowCount() > rowIndex) {
        switch (columnId) {
            case "fixWrkUnitNo":
                if (ds_fix_work_unit.getCellData(rowIndex, columnId) != "" && ds_fix_work_unit.getCellData(rowIndex, columnId) != oldValue) {
                    ds_fix_work_unit.setCellData(rowIndex, "fixWrkUnitNm", "");
                    scwin.f_openCommPopUpGrid(2, rowIndex, 'T');
                } else if (ds_fix_work_unit.getCellData(rowIndex, columnId) == "") {
                    ds_fix_work_unit.setCellData(rowIndex, "fixWrkUnitNo", "");
                    ds_fix_work_unit.setCellData(rowIndex, "fixWrkUnitNm", "");
                    scwin.f_applyFixWorkUnit(rowIndex, ds_fix_work_unit.getCellData(rowIndex, "fixWrkUnitNo"));
                }

                if (lux_selfOutordClsCd.getValue() == "IN") {
                    if (ds_fix_work_unit.getRowStatus(rowIndex) != "C") return;
                    if (ds_fix_work_unit.getCellData(rowIndex, "fixWrkUnitNo") == "") return;
                    scwin.f_AddRow(3);
                    ds_fix_driver.setCellData(ds_fix_driver.getRowPosition(), "fixWrkUnitNo", ds_fix_work_unit.getCellData(rowIndex, columnId));
                }
                break;
        }
    }
    scwin.f_setAdjustment();
};

