scwin.gr_repair_circula_parts_oneditend = function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    if (rowIndex >= 0 && ds_repair_circula_parts.getRowCount() > rowIndex) {
        switch (columnId) {
            case "circulPartCd":
