    if (rowIndex >= 0 && ds_fix_work_parts.getRowCount() > rowIndex) {
        switch (columnId) {
            case "fixWrkUnitNo":
                scwin.f_openCommPopUpGrid(6, rowIndex, 'F');
                break;
            case "partCd":
                scwin.f_openCommPopUpGrid(7, rowIndex, 'F');
                break;
        }
    }
};

scwin.gr_fix_work_parts_oneditend = function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    if (rowIndex >= 0 && ds_fix_work_parts.getRowCount() > rowIndex) {
        switch (columnId) {
            case "fixWrkUnitNo":
                if (ds_fix_work_parts.getCellData(rowIndex, columnId) != "" && ds_fix_work_parts.getCellData(rowIndex, columnId) != oldValue) {
                    scwin.f_openCommPopUpGrid(6, rowIndex, 'T');
                } else if (ds_fix_work_parts.getCellData(rowIndex, columnId) == "") {
                    ds_fix_work_parts.setCellData(rowIndex, "fixWrkUnitNo", "");
                }
                break;
            case "partCd":
                if (ds_fix_work_parts.getCellData(rowIndex, columnId) != "" && ds_fix_work_parts.getCellData(rowIndex, columnId) != oldValue) {
                    ds_fix_work_parts.setCellData(rowIndex, "partNm", "");
                    ds_fix_work_parts.setCellData(rowIndex, "partUnitNm", "");
                    scwin.f_openCommPopUpGrid(7, rowIndex, 'T');
                } else if (ds_fix_work_parts.getCellData(rowIndex, columnId) == "") {
                    ds_fix_work_parts.setCellData(rowIndex, "partCd", "");
                    ds_fix_work_parts.setCellData(rowIndex, "partNm", "");
                    ds_fix_work_parts.setCellData(rowIndex, "partUnitNm", "");
                }
                break;
            case "partQty":
                if (ds_fix_work_parts.getCellData(rowIndex, "partQty") == "0") {
                    ds_fix_work_parts.setCellData(rowIndex, "totAmt", "0");
                    ds_fix_work_parts.setCellData(rowIndex, "vatAmt", "0");
                } else {
                    ds_fix_work_parts.setCellData(rowIndex, "totAmt", ds_fix_work_parts.getCellData(rowIndex, "partQty") * ds_fix_work_parts.getCellData(rowIndex, "outUpr"));
                    ds_fix_work_parts.setCellData(rowIndex, "vatAmt", ds_fix_work_parts.getCellData(rowIndex, "totAmt") / 10);
                }
                break;
        }
    }
    scwin.f_setAdjustment();
};

