scwin.em_wrkStHh_onblur = async function(e) {
    if (em_wrkStHh.getValue() != "" && (em_wrkStHh.getValue().length < 4 || em_wrkStHh.getValue().substring(0, 2) > "24" || em_wrkStHh.getValue().substring(2, 4) > "59" || em_wrkStHh.getValue() > "2459")) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["작업시작시각"]);
        em_wrkStHh.setValue("");
        em_wrkStHh.setFocus();
    }
};

