scwin.ica_wrkStDt_onblur = async function(e) {
    if (ica_wrkEndDt.getValue() != "") {
        let chk1 = await $c.gus.cfValidate([ica_wrkEndDt]);
        let chk2 = await $c.gus.cfValidate([ica_wrkStDt]);
        if (chk1 && chk2) {
            em_needDt.setValue($c.date.diffDate(ica_wrkStDt.getValue(), ica_wrkEndDt.getValue()));
        }
    }
    if (em_wrkIntendDt.getValue() == "") {
        em_wrkIntendDt.setValue(ica_wrkStDt.getValue());
    }
};

scwin.ica_wrkEndDt_onblur = async function(e) {
    if (ica_wrkStDt.getValue() != "") {
        let chk1 = await $c.gus.cfValidate([ica_wrkStDt]);
        let chk2 = await $c.gus.cfValidate([ica_wrkEndDt]);
        if (chk1 && chk2) {
            em_needDt.setValue($c.date.diffDate(ica_wrkStDt.getValue(), ica_wrkEndDt.getValue()));
        }
    }
    if (em_endIntendDt.getValue() == "") {
        em_endIntendDt.setValue(ica_wrkEndDt.getValue());
    }
};

scwin.ds_fix_work_standard_onrowpositionchange = function(rowIndex, oldRowIndex) {
    if (rowIndex < 0) return;
    if (ds_fix_work_standard.getRowStatus(rowIndex) == "C") {
        gr_fix_work_standard.setColumnReadOnly("fixWrkStndNo", false);
        gr_fix_work_standard2.setColumnReadOnly("fixWrkStndNo", false);
    } else {
        gr_fix_work_standard.setColumnReadOnly("fixWrkStndNo", true);
        gr_fix_work_standard2.setColumnReadOnly("fixWrkStndNo", true);
    }
};

scwin.ds_fix_work_unit_onrowpositionchange = function(rowIndex, oldRowIndex) {
