scwin.ds_repair_circula_parts_onrowpositionchange = function(rowIndex, oldRowIndex) {
    if (rowIndex < 0) return;
    if (ds_repair_circula_parts.getRowStatus(rowIndex) == "C") {
        gr_repair_circula_parts.setColumnReadOnly("attDetClsCd", false);
        gr_repair_circula_parts.setColumnReadOnly("circulPartCd", false);
    } else {
        gr_repair_circula_parts.setColumnReadOnly("attDetClsCd", true);
        gr_repair_circula_parts.setColumnReadOnly("circulPartCd", true);
    }
};

scwin.ds_fix_work_parts_onrowpositionchange = function(rowIndex, oldRowIndex) {
    if (rowIndex < 0) return;
    if (ds_fix_work_parts.getCellData(rowIndex, "partOutNo") != "") {
        if (lux_selfOutordClsCd.getValue() == "IN") {
            gr_fix_work_parts.setColumnReadOnly("fixWrkUnitNo", true);
            gr_fix_work_parts.setColumnReadOnly("partCd", true);
            gr_fix_work_parts.setColumnReadOnly("partQty", true);
            gr_fix_work_parts.setColumnReadOnly("inClsCd", true);
        } else {
            gr_repair_circula_parts2.setColumnReadOnly("fixWrkUnitNo", true);
            gr_repair_circula_parts2.setColumnReadOnly("partCd", true);
            gr_repair_circula_parts2.setColumnReadOnly("partQty", true);
            gr_repair_circula_parts2.setColumnReadOnly("inClsCd", true);
        }
    } else {
        if (lux_selfOutordClsCd.getValue() == "IN") {
            gr_fix_work_parts.setColumnReadOnly("fixWrkUnitNo", false);
            gr_fix_work_parts.setColumnReadOnly("partCd", false);
            gr_fix_work_parts.setColumnReadOnly("partQty", false);
            gr_fix_work_parts.setColumnReadOnly("inClsCd", false);
        } else {
            gr_repair_circula_parts2.setColumnReadOnly("fixWrkUnitNo", false);
            gr_repair_circula_parts2.setColumnReadOnly("partCd", false);
            gr_repair_circula_parts2.setColumnReadOnly("partQty", false);
            gr_repair_circula_parts2.setColumnReadOnly("inClsCd", false);
        }
    }
};
